  if (base === "kw") return [{ type: "sql native", rawType: "kw" }];
  if (base === "T" || base === "any") return ["string", "number", "boolean", "date", "timestamp", "json", "array"].map((type) => ({ type }));
  if (base === "array") return [{ type: "array" }];
